import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithDelimiter() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        char delimiter = ',';
        CSVFormat csvFormat = new CSVFormat('|', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        Method withDelimiterMethod = CSVFormat.class.getDeclaredMethod("withDelimiter", char.class);
        withDelimiterMethod.setAccessible(true);
        CSVFormat result = (CSVFormat) withDelimiterMethod.invoke(csvFormat, delimiter);

        // Then
        assertNotEquals(csvFormat, result);
        assertEquals(delimiter, result.getDelimiter());
    }

    @Test
    public void testWithDelimiter_lineBreakDelimiter_exceptionThrown() {
        // Given
        char lineBreakDelimiter = '\n';
        CSVFormat csvFormat = new CSVFormat('|', '\"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When & Then
        assertThrows(IllegalArgumentException.class, () -> csvFormat.withDelimiter(lineBreakDelimiter));
    }
}
